from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'

# In-memory storage (use a database in production)
users_db = {
    'admin': {
        'password_hash': hashlib.sha256('admin123'.encode()).hexdigest(),
        'name': 'Admin User'
    },
    'john': {
        'password_hash': hashlib.sha256('john123'.encode()).hexdigest(),
        'name': 'John Doe'
    }
}

# Token storage: token -> {username, created_at, expires_at}
active_tokens = {}


def generate_token():
    """Generate a secure random token."""
    return secrets.token_hex(32)


def hash_password(password):
    """Hash a password using SHA-256."""
    return hashlib.sha256(password.encode()).hexdigest()


def cleanup_expired_tokens():
    """Remove expired tokens from storage."""
    now = datetime.datetime.utcnow()
    expired = [token for token, data in active_tokens.items() if data['expires_at'] < now]
    for token in expired:
        del active_tokens[token]


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check for token in Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header:
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        # Also check query parameter as fallback
        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({
                'success': False,
                'message': 'Authentication token is missing. Provide it via Authorization header (Bearer <token>) or query parameter.'
            }), 401

        # Clean up expired tokens
        cleanup_expired_tokens()

        # Validate token
        token_data = active_tokens.get(token)
        if not token_data:
            return jsonify({
                'success': False,
                'message': 'Token is invalid or has expired.'
            }), 401

        # Check expiration
        if token_data['expires_at'] < datetime.datetime.utcnow():
            del active_tokens[token]
            return jsonify({
                'success': False,
                'message': 'Token has expired. Please login again.'
            }), 401

        # Pass current user info to the route
        current_user = {
            'username': token_data['username'],
            'name': users_db[token_data['username']]['name']
        }

        return f(current_user, *args, **kwargs)

    return decorated


@app.route('/', methods=['GET'])
def home():
    """Public home endpoint."""
    return jsonify({
        'success': True,
        'message': 'Welcome to the API Authentication System',
        'endpoints': {
            'POST /register': 'Register a new user (username, password, name)',
            'POST /login': 'Login and receive a token (username, password)',
            'POST /logout': 'Logout and invalidate token (requires token)',
            'GET /protected': 'Access protected resource (requires token)',
            'GET /profile': 'Get user profile (requires token)',
            'GET /users': 'List all users (requires token)',
        }
    })


@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = data.get('username')
    password = data.get('password')
    name = data.get('name', username)

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    if len(password) < 6:
        return jsonify({
            'success': False,
            'message': 'Password must be at least 6 characters long.'
        }), 400

    if username in users_db:
        return jsonify({
            'success': False,
            'message': 'Username already exists.'
        }), 409

    users_db[username] = {
        'password_hash': hash_password(password),
        'name': name
    }

    return jsonify({
        'success': True,
        'message': f'User "{username}" registered successfully.'
    }), 201


@app.route('/login', methods=['POST'])
def login():
    """Authenticate user and return a token."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON with username and password.'
        }), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    # Verify user exists
    user = users_db.get(username)
    if not user:
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    # Verify password
    if user['password_hash'] != hash_password(password):
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    # Generate token
    token = generate_token()
    now = datetime.datetime.utcnow()
    expires_at = now + datetime.timedelta(hours=24)

    active_tokens[token] = {
        'username': username,
        'created_at': now,
        'expires_at': expires_at
    }

    # Clean up expired tokens periodically
    cleanup_expired_tokens()

    return jsonify({
        'success': True,
        'message': 'Login successful.',
        'data': {
            'token': token,
            'token_type': 'Bearer',
            'expires_in': '24 hours',
            'expires_at': expires_at.isoformat() + 'Z',
            'user': {
                'username': username,
                'name': user['name']
            }
        }
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user):
    """Logout and invalidate the current token."""
    auth_header = request.headers.get('Authorization')
    token = None

    if auth_header:
        parts = auth_header.split()
        if len(parts) == 2:
            token = parts[1]

    if not token:
        token = request.args.get('token')

    if token and token in active_tokens:
        del active_tokens[token]

    return jsonify({
        'success': True,
        'message': f'User "{current_user["username"]}" logged out successfully. Token has been invalidated.'
    }), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user):
    """A protected endpoint that requires authentication."""
    return jsonify({
        'success': True,
        'message': 'You have access to this protected resource!',
        'data': {
            'current_user': current_user,
            'secret_info': 'This is confidential data only visible to authenticated users.',
            'timestamp': datetime.datetime.utcnow().isoformat() + 'Z'
        }
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(current_user):
    """Get the current user's profile."""
    user_data = users_db.get(current_user['username'])

    # Count active tokens for this user
    user_sessions = sum(
        1 for data in active_tokens.values()
        if data['username'] == current_user['username']
    )

    return jsonify({
        'success': True,
        'data': {
            'username': current_user['username'],
            'name': user_data['name'],
            'active_sessions': user_sessions
        }
    }), 200


@app.route('/users', methods=['GET'])
@token_required
def list_users(current_user):
    """List all registered users (admin-like endpoint)."""
    users_list = [
        {'username': username, 'name': data['name']}
        for username, data in users_db.items()
    ]

    return jsonify({
        'success': True,
        'data': {
            'total_users': len(users_list),
            'users': users_list,
            'requested_by': current_user['username']
        }
    }), 200


